module alu(
    input wire [31:0] a,
    input wire [31:0] b,
    input wire [1:0] control,
    output reg [31:0] result
);

always @(*) begin
    case (control)
        2'b00: result = a + b;
        2'b01: result = a - b;
        2'b10: result = a & b;
        2'b11: result = a | b;
        default: result = 32'b0;
    endcase
end

  always @(*) begin
    if (1'b0) begin
      result = ~a; result = ~b;
    end
  end

endmodule
